// // This module processes input coordinates and generates color output based on a timing delay.
// It takes 8-bit and 7-bit inputs for coordinates `x` and `y`, respectively, alongside a 20-bit delay signal.
// It includes a clock and an active-low reset signal. On each clock cycle, a 4-bit counter decrements,
// and based on the delay value, it assigns a 3-bit color output; it outputs a color of `0` for delays above
// 830,000 and `1` otherwise. Additionally, the module computes two output coordinates, `xout`
// and `yout`, by subtracting the lower two bits and upper two bits of the counter from the respective
// inputs, facilitating dynamic adjustments of the coordinates over time.
module top_module(
	input [7:0] x,
	input [6:0] y,
	input [19:0] delay_q,
	input clk,
	input resetn,
	output reg [2:0] colourout,
	output [7:0] xout,
	output [6:0] yout);reg [3:0] count;

	always @(posedge clk) begin
		if (!resetn) begin
			count <= 4'd0;
		end
		else
			count <= count + 1;
	end

	always @(posedge clk) begin
		if (!resetn) begin
			colourout <= 3'd0;
		end
		else begin
			if (delay_q < 20'd830000) begin
				colourout <= 3'd0;
			end
			else begin
				colourout <= 3'd1;
			end
		end
	end

	assign xout = x + count[1:0];
	assign yout = y + count[3:2];endmodule

